import requests

# ngrok public URL. need to change this every time ngrok is restarted
ngrok_url = "https://06c9-203-123-111-82.ngrok-free.app/upload-image"

# example image data
image_data = ""


# Create the payload as a JSON object
payload = {
    "image": image_data
}

# Send the POST request to Flask server
response = requests.post(ngrok_url, json=payload, timeout=10)

# Print the server's response
print(response.status_code)
print(response.json())
